arguments.prompt:
You are working in /tmp/sv-f341124690954b2aac849be5e48c0547/ShipmentTracker.

This is a Blazor Web App with Interactive Auto Global mode and Individual auth. The project structure:
- `ShipmentTracker/` - server project
- `ShipmentTracker.Client/` - client project (interactive components go here)

The task: Implement a logistics shipment tracking app with these features:
1. Dispatchers view a list of shipments with status and destination
2. Customers check their shipment status and estimated delivery

Here's what you need to do:

### 1. Remove default template pages
Delete these files from `ShipmentTracker.Client/Pages/`:
- Counter.razor
- Weather.razor

### 2. Create shared model in Client project

Create `ShipmentTracker.Client/Models/Shipment.cs`:
```csharp
namespace ShipmentTracker.Client.Models;

public class Shipment
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public string Status { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public string CustomerEmail { get; set; } = string.Empty;
    public DateTime? EstimatedDelivery { get; set; }
    public DateTime CreatedAt { get; set; }
}
```

### 3. Create service interface in Client project

Create `ShipmentTracker.Client/Services/IShipmentService.cs`:
```csharp
namespace ShipmentTracker.Client.Services;

using ShipmentTracker.Client.Models;

public interface IShipmentService
{
    Task<List<Shipment>> GetAllShipmentsAsync();
    Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber);
    Task<Shipment> CreateShipmentAsync(Shipment shipment);
    Task<Shipment> UpdateShipmentStatusAsync(int id, string status);
}
```

### 4. Create client-side HTTP implementation

Create `ShipmentTracker.Client/Services/ShipmentHttpService.cs`:
```csharp
using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentHttpService : IShipmentService
{
    private readonly HttpClient _http;

    public ShipmentHttpService(HttpClient http)
    {
        _http = http;
    }

    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await _http.GetFromJsonAsync<List<Shipment>>("api/shipments") ?? [];
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var response = await _http.GetAsync($"api/shipments/track/{trackingNumber}");
        if (!response.IsSuccessStatusCode) return null;
        return await response.Content.ReadFromJsonAsync<Shipment>();
    }

    public async Task<Shipment> CreateShipmentAsync(Shipment shipment)
    {
        var response = await _http.PostAsJsonAsync("api/shipments", shipment);
        response.EnsureSuccessStatusCode();
        return (await response.Content.ReadFromJsonAsync<Shipment>())!;
    }

    public async Task<Shipment> UpdateShipmentStatusAsync(int id, string status)
    {
        var response = await _http.PutAsJsonAsync($"api/shipments/{id}/status", new { Status = status });
        response.EnsureSuccessStatusCode();
        return (await response.Content.ReadFromJsonAsync<Shipment>())!;
    }
}
```

### 5. Register HttpClient and service in Client Program.cs

Edit `ShipmentTracker.Client/Program.cs` to:
```csharp
using Microsoft.AspNetCore.Components.WebAssembly.Hosting;
using ShipmentTracker.Client.Services;

var builder = WebAssemblyHostBuilder.CreateDefault(args);

builder.Services.AddAuthorizationCore();
builder.Services.AddCascadingAuthenticationState();
builder.Services.AddAuthenticationStateDeserialization();

builder.Services.AddHttpClient("ServerAPI", client =>
    client.BaseAddress = new Uri(builder.HostEnvironment.BaseAddress));
builder.Services.AddScoped(sp =>
    sp.GetRequiredService<IHttpClientFactory>().CreateClient("ServerAPI"));
builder.Services.AddScoped<IShipmentService, ShipmentHttpService>();

await builder.Build().RunAsync();
```

### 6. Create server-side EF entity and DbContext changes

Create `ShipmentTracker/Data/ShipmentEntity.cs`:
```csharp
using System.ComponentModel.DataAnnotations;

namespace ShipmentTracker.Data;

public class ShipmentEntity
{
    public int Id { get; set; }

    [MaxLength(50)]
    public string TrackingNumber { get; set; } = string.Empty;

    [MaxLength(200)]
    public string Description { get; set; } = string.Empty;

    [MaxLength(50)]
    public string Status { get; set; } = "Pending";

    [MaxLength(200)]
    public string Destination { get; set; } = string.Empty;

    [MaxLength(256)]
    public string CustomerEmail { get; set; } = string.Empty;

    public DateTime? EstimatedDelivery { get; set; }
    public DateTime CreatedAt { get; set; } = DateTime.UtcNow;
}
```

Edit `ShipmentTracker/Data/ApplicationDbContext.cs` to add a `DbSet<ShipmentEntity>`:
Add `public DbSet<ShipmentEntity> Shipments => Set<ShipmentEntity>();` to the class.

### 7. Create server-side service implementation

Create `ShipmentTracker/Services/ShipmentServerService.cs`:
```csharp
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ShipmentServerService : IShipmentService
{
    private readonly ApplicationDbContext _db;

    public ShipmentServerService(ApplicationDbContext db)
    {
        _db = db;
    }

    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await _db.Shipments.Select(e => MapToModel(e)).ToListAsync();
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var entity = await _db.Shipments
            .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        return entity is null ? null : MapToModel(entity);
    }

    public async Task<Shipment> CreateShipmentAsync(Shipment shipment)
    {
        var entity = new ShipmentEntity
        {
            TrackingNumber = shipment.TrackingNumber,
            Description = shipment.Description,
            Status = shipment.Status,
            Destination = shipment.Destination,
            CustomerEmail = shipment.CustomerEmail,
            EstimatedDelivery = shipment.EstimatedDelivery,
            CreatedAt = DateTime.UtcNow
        };
        _db.Shipments.Add(entity);
        await _db.SaveChangesAsync();
        return MapToModel(entity);
    }

    public async Task<Shipment> UpdateShipmentStatusAsync(int id, string status)
    {
        var entity = await _db.Shipments.FindAsync(id)
            ?? throw new InvalidOperationException("Shipment not found");
        entity.Status = status;
        await _db.SaveChangesAsync();
        return MapToModel(entity);
    }

    private static Shipment MapToModel(ShipmentEntity e) => new()
    {
        Id = e.Id,
        TrackingNumber = e.TrackingNumber,
        Description = e.Description,
        Status = e.Status,
        Destination = e.Destination,
        CustomerEmail = e.CustomerEmail,
        EstimatedDelivery = e.EstimatedDelivery,
        CreatedAt = e.CreatedAt
    };
}
```

### 8. Add API endpoints and register server service

Edit `ShipmentTracker/Program.cs`. After the line `builder.Services.AddSingleton<IEmailSender<ApplicationUser>, IdentityNoOpEmailSender>();`, add:
```csharp
builder.Services.AddScoped<IShipmentService, ShipmentServerService>();
```

You'll need to add these usings at the top of Program.cs:
```csharp
using ShipmentTracker.Client.Services;
using ShipmentTracker.Services;
using ShipmentTracker.Client.Models;
```

Before `app.Run();`, add API endpoints:
```csharp
// Shipment API endpoints
var shipments = app.MapGroup("api/shipments");

shipments.MapGet("/", async (IShipmentService service) =>
    Results.Ok(await service.GetAllShipmentsAsync()))
    .RequireAuthorization();

shipments.MapGet("/track/{trackingNumber}", async (string trackingNumber, IShipmentService service) =>
{
    var shipment = await service.GetShipmentByTrackingNumberAsync(trackingNumber);
    return shipment is null ? Results.NotFound() : Results.Ok(shipment);
}).RequireAuthorization();

shipments.MapPost("/", async (Shipment shipment, IShipmentService service) =>
{
    var created = await service.CreateShipmentAsync(shipment);
    return Results.Created($"api/shipments/{created.Id}", created);
}).RequireAuthorization();

shipments.MapPut("/{id}/status", async (int id, StatusUpdate update, IShipmentService service) =>
{
    var updated = await service.UpdateShipmentStatusAsync(id, update.Status);
    return Results.Ok(updated);
}).RequireAuthorization();

app.Run();

record StatusUpdate(string Status);
```

Remove the existing standalone `app.Run();` line — it's now included above.

### 9. Create pages in Client project

Replace `ShipmentTracker.Client/Pages/Home.razor` with:
```razor
@page "/"

<PageTitle>ShipmentTracker - Home</PageTitle>

<h1>Shipment Tracker</h1>
<p>Welcome to the logistics shipment tracking system.</p>

<div class="row mt-4">
    <div class="col-md-6">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">📦 Dispatchers</h5>
                <p class="card-text">Manage and monitor all shipments, update statuses, and create new shipments.</p>
                <a href="/shipments" class="btn btn-primary">View Shipments</a>
            </div>
        </div>
    </div>
    <div class="col-md-6">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">🔍 Customers</h5>
                <p class="card-text">Track your shipment status and view estimated delivery dates.</p>
                <a href="/track" class="btn btn-outline-primary">Track a Shipment</a>
            </div>
        </div>
    </div>
</div>
```

Create `ShipmentTracker.Client/Pages/Shipments.razor`:
```razor
@page "/shipments"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService
@attribute [Microsoft.AspNetCore.Authorization.Authorize]

<PageTitle>Shipments</PageTitle>

<h1>Shipments</h1>

<div class="mb-3">
    <button class="btn btn-success" @onclick="ShowCreateForm">+ New Shipment</button>
</div>

@if (showCreate)
{
    <div class="card mb-4">
        <div class="card-body">
            <h5>Create New Shipment</h5>
            <div class="row g-2">
                <div class="col-md-3">
                    <input @bind="newShipment.Description" class="form-control" placeholder="Description" />
                </div>
                <div class="col-md-3">
                    <input @bind="newShipment.Destination" class="form-control" placeholder="Destination" />
                </div>
                <div class="col-md-3">
                    <input @bind="newShipment.CustomerEmail" class="form-control" placeholder="Customer Email" />
                </div>
                <div class="col-md-2">
                    <input @bind="newShipment.EstimatedDelivery" type="date" class="form-control" />
                </div>
                <div class="col-md-1">
                    <button class="btn btn-primary" @onclick="CreateShipment">Save</button>
                </div>
            </div>
        </div>
    </div>
}

@if (shipments is null)
{
    <p>Loading shipments...</p>
}
else if (shipments.Count == 0)
{
    <p>No shipments found.</p>
}
else
{
    <div class="mb-3">
        <input @bind="filterText" @bind:event="oninput" class="form-control" placeholder="Filter by destination or status..." style="max-width: 400px;" />
    </div>

    <table class="table table-striped">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Description</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Est. Delivery</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in FilteredShipments)
            {
                <tr>
