Before `app.Run();`, add API endpoints:
```csharp
// Shipment API endpoints
var shipments = app.MapGroup("api/shipments");

shipments.MapGet("/", async (IShipmentService service) =>
    Results.Ok(await service.GetAllShipmentsAsync()))
    .RequireAuthorization();

shipments.MapGet("/track/{trackingNumber}", async (string trackingNumber, IShipmentService service) =>
{
    var shipment = await service.GetShipmentByTrackingNumberAsync(trackingNumber);
    return shipment is null ? Results.NotFound() : Results.Ok(shipment);
}).RequireAuthorization();

shipments.MapPost("/", async (Shipment shipment, IShipmentService service) =>
{
    var created = await service.CreateShipmentAsync(shipment);
    return Results.Created($"api/shipments/{created.Id}", created);
}).RequireAuthorization();

shipments.MapPut("/{id}/status", async (int id, StatusUpdate update, IShipmentService service) =>
{
    var updated = await service.UpdateShipmentStatusAsync(id, update.Status);
    return Results.Ok(updated);
}).RequireAuthorization();

app.Run();

record StatusUpdate(string Status);
```

