@code {
    private List<Shipment>? shipments;
    private bool showCreate;
    private Shipment newShipment = new();
    private string filterText = string.Empty;

    private IEnumerable<Shipment> FilteredShipments =>
        shipments?.Where(s =>
            string.IsNullOrWhiteSpace(filterText) ||
            s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
            s.Status.Contains(filterText, StringComparison.OrdinalIgnoreCase)) ?? [];

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private void ShowCreateForm() => showCreate = !showCreate;

    private async Task CreateShipment()
    {
        newShipment.TrackingNumber = $"TRK-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(1000, 9999)}";
        newShipment.Status = "Pending";
        var created = await ShipmentService.CreateShipmentAsync(newShipment);
        shipments?.Insert(0, created);
        newShipment = new();
        showCreate = false;
    }

    private async Task UpdateStatus(int id, string status)
    {
        if (string.IsNullOrEmpty(status)) return;
        var updated = await ShipmentService.UpdateShipmentStatusAsync(id, status);
        var idx = shipments?.FindIndex(s => s.Id == id) ?? -1;
        if (idx >= 0 && shipments is not null)
            shipments[idx] = updated;
    }

    private static string GetStatusBadgeClass(string status) => status switch
    {
        "Pending" => "bg-secondary",
        "In Transit" => "bg-primary",
        "Out for Delivery" => "bg-info",
        "Delivered" => "bg-success",
        "Delayed" => "bg-warning text-dark",
        _ => "bg-secondary"
    };
}
