        if (string.IsNullOrEmpty(status)) return;
        var updated = await ShipmentService.UpdateShipmentStatusAsync(id, status);
        var idx = shipments?.FindIndex(s => s.Id == id) ?? -1;
        if (idx >= 0 && shipments is not null)
            shipments[idx] = updated;
    }

    private static string GetStatusBadgeClass(string status) => status switch
    {
        "Pending" => "bg-secondary",
        "In Transit" => "bg-primary",
        "Out for Delivery" => "bg-info",
        "Delivered" => "bg-success",
        "Delayed" => "bg-warning text-dark",
        _ => "bg-secondary"
    };
}

@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService
@attribute [Microsoft.AspNetCore.Authorization.Authorize]

<PageTitle>Track Shipment</PageTitle>

<h1>Track Your Shipment</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input @bind="trackingNumber" @onkeydown="HandleKeyDown" class="form-control" placeholder="Enter tracking number (e.g., TRK-20260522-1234)" />
            <button class="btn btn-primary" @onclick="TrackShipment">Track</button>
        </div>
    </div>
</div>

@if (isLoading)
{
    <p>Searching...</p>
}
else if (searched && shipment is null)
{
    <div class="alert alert-warning">
        No shipment found with tracking number <strong>@searchedNumber</strong>.
    </div>
}
else if (shipment is not null)
{
    <div class="card" style="max-width: 600px;">
        <div class="card-header">
            <strong>Tracking #:</strong> @shipment.TrackingNumber
        </div>
        <div class="card-body">
            <table class="table table-borderless mb-0">
                <tbody>
                    <tr>
                        <th>Description</th>
                        <td>@shipment.Description</td>
                    </tr>
                    <tr>
                        <th>Destination</th>
                        <td>@shipment.Destination</td>
                    </tr>
                    <tr>
                        <th>Status</th>
                        <td><span class="badge @GetStatusBadgeClass(shipment.Status) fs-6">@shipment.Status</span></td>
                    </tr>
                    <tr>
                        <th>Estimated Delivery</th>
                        <td>
                            @if (shipment.EstimatedDelivery.HasValue)
                            {
                                <strong>@shipment.EstimatedDelivery.Value.ToString("dddd, MMMM dd, yyyy")</strong>
                            }
                            else
                            {
                                <span class="text-muted">Not yet scheduled</span>
                            }
                        </td>
                    </tr>
                    <tr>
                        <th>Shipped On</th>
                        <td>@shipment.CreatedAt.ToString("MMMM dd, yyyy")</td>
                    </tr>
                </tbody>
            </table>
        </div>
    </div>
}

@code {
    private string trackingNumber = string.Empty;
